
/**
 * Client
**/

import * as runtime from '@prisma/client/runtime/client.js';
import $Types = runtime.Types // general types
import $Public = runtime.Types.Public
import $Utils = runtime.Types.Utils
import $Extensions = runtime.Types.Extensions
import $Result = runtime.Types.Result

export type PrismaPromise<T> = $Public.PrismaPromise<T>


/**
 * Model Profile
 * Extended user profile — 1:1 with auth.users.
 * Stores lifestyle/environment factors for Dynamic Norm computation.
 */
export type Profile = $Result.DefaultSelection<Prisma.$ProfilePayload>
/**
 * Model Feedback
 * User feedback (bug reports, suggestions, etc)
 */
export type Feedback = $Result.DefaultSelection<Prisma.$FeedbackPayload>
/**
 * Model ActiveConditionKnowledgeBase
 * Temporary/Active Knowledge Base tied to a specific user clinical condition
 * (e.g., Latent Anemia). Injected into AI context until resolved.
 */
export type ActiveConditionKnowledgeBase = $Result.DefaultSelection<Prisma.$ActiveConditionKnowledgeBasePayload>
/**
 * Model EnvironmentReading
 * Real-time environmental telemetry (AQI, UV, pollen).
 * Composite index on (userId, recordedAt) for fast time-range queries.
 */
export type EnvironmentReading = $Result.DefaultSelection<Prisma.$EnvironmentReadingPayload>
/**
 * Model WaterQualitySnapshot
 * Periodic drinking water quality snapshot.
 */
export type WaterQualitySnapshot = $Result.DefaultSelection<Prisma.$WaterQualitySnapshotPayload>
/**
 * Model Biomarker
 * Reference catalog of all supported blood/lab markers.
 * Read-only for users; writable via service_role.
 */
export type Biomarker = $Result.DefaultSelection<Prisma.$BiomarkerPayload>
/**
 * Model TestSession
 * Groups multiple test_results from the same blood draw.
 */
export type TestSession = $Result.DefaultSelection<Prisma.$TestSessionPayload>
/**
 * Model TestResult
 * Individual biomarker measurement from a lab report.
 * Composite index on (userId, testDate DESC) for timeline queries.
 */
export type TestResult = $Result.DefaultSelection<Prisma.$TestResultPayload>
/**
 * Model DynamicNormRule
 * Rules for shifting biomarker reference ranges based on lifestyle factors.
 * Core intellectual property of the Dynamic Norm engine.
 */
export type DynamicNormRule = $Result.DefaultSelection<Prisma.$DynamicNormRulePayload>
/**
 * Model UserDynamicNorm
 * Cached personalized reference range per user per biomarker.
 * Recalculated when profile or rules change.
 */
export type UserDynamicNorm = $Result.DefaultSelection<Prisma.$UserDynamicNormPayload>
/**
 * Model AiChatMessage
 * Stores conversation history for the AI assistant and food diary.
 * This prevents Prisma from dropping the table during `db push`.
 */
export type AiChatMessage = $Result.DefaultSelection<Prisma.$AiChatMessagePayload>
/**
 * Model GeneticVariant
 * Known genetic variant/polymorphism from DNA testing services.
 * CYP1A2, MTHFR, APOE, MCM6, etc.
 */
export type GeneticVariant = $Result.DefaultSelection<Prisma.$GeneticVariantPayload>
/**
 * Model Medication
 * Current medication or supplement a user is taking.
 */
export type Medication = $Result.DefaultSelection<Prisma.$MedicationPayload>
/**
 * Model SupplementLog
 * Phase 51: Supplement intake log for compliance tracking
 */
export type SupplementLog = $Result.DefaultSelection<Prisma.$SupplementLogPayload>
/**
 * Model InteractionAlert
 * AI-generated alert for drug–drug, drug–supplement, or drug–gene interactions.
 */
export type InteractionAlert = $Result.DefaultSelection<Prisma.$InteractionAlertPayload>
/**
 * Model WaterLog
 * User-logged water intake
 */
export type WaterLog = $Result.DefaultSelection<Prisma.$WaterLogPayload>
/**
 * Model FoodItem
 * Reference food item with nutritional profile (not user-scoped).
 */
export type FoodItem = $Result.DefaultSelection<Prisma.$FoodItemPayload>
/**
 * Model MealLog
 * A logged meal with timing and AI-computed quality score.
 */
export type MealLog = $Result.DefaultSelection<Prisma.$MealLogPayload>
/**
 * Model MealItem
 * Explicit join: a food item in a meal with portion size.
 */
export type MealItem = $Result.DefaultSelection<Prisma.$MealItemPayload>
/**
 * Model CgmReading
 * CGM time-series data point (every 1–15 minutes).
 * Composite index on (userId, recordedAt) — critical for glucose curve queries.
 */
export type CgmReading = $Result.DefaultSelection<Prisma.$CgmReadingPayload>
/**
 * Model GutSymptomLog
 * User-reported gut/digestive symptom log.
 * Linked to meals for food–symptom correlation.
 */
export type GutSymptomLog = $Result.DefaultSelection<Prisma.$GutSymptomLogPayload>
/**
 * Model SleepSession
 * A single night's sleep session from a wearable device.
 * Composite index for fast date-range queries per user.
 */
export type SleepSession = $Result.DefaultSelection<Prisma.$SleepSessionPayload>
/**
 * Model HrvReading
 * Heart Rate Variability reading — the master recovery indicator.
 * Captured during sleep or morning spot-check.
 */
export type HrvReading = $Result.DefaultSelection<Prisma.$HrvReadingPayload>
/**
 * Model ReadinessScore
 * Morning readiness score computed from sleep + HRV.
 * One per user per day.
 */
export type ReadinessScore = $Result.DefaultSelection<Prisma.$ReadinessScorePayload>
/**
 * Model HealthspanScore
 * Master "Biological Age" / Healthspan Score record.
 * Synthesizes data from all 4 input domains into a single composite score.
 */
export type HealthspanScore = $Result.DefaultSelection<Prisma.$HealthspanScorePayload>
/**
 * Model AiInsight
 * AI-generated insight/recommendation from cross-domain analysis.
 */
export type AiInsight = $Result.DefaultSelection<Prisma.$AiInsightPayload>

